@using sv_55b36ea3ed17461fbfcbf6544a3e6739.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar ── *@
    <aside class="channel-sidebar">
        <h3 class="sidebar-title">Channels</h3>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(threadOpen ? "" : "expanded")">
        @if (activeChannel is not null)
        {
            <header class="message-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </header>

            <div class="message-list" @ref="messageListRef" @onscroll="HandleScrollAsync">
                @if (isLoadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-card" @onmouseenter="() => hoveredMessageId = msg.Id"
                         @onmouseleave="() => hoveredMessageId = null">
                        <div class="message-meta">
                            <strong class="message-author">@msg.Author</strong>
                            <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                        </div>
                        <div class="message-content">@msg.Content</div>

                        @if (msg.Reactions.Count > 0)
                        {
                            <div class="reaction-row">
                                @foreach (var r in msg.Reactions)
                                {
                                    <button class="reaction-badge" @onclick="() => AddReactionAsync(msg.Id, r.Emoji)"
                                            title="@string.Join(", ", r.Users)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }

                        @{ var threadInfo = threadSummaries.GetValueOrDefault(msg.Id); }
                        @if (threadInfo is not null)
                        {
                            <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                @threadInfo.ReplyCount @(threadInfo.ReplyCount == 1 ? "reply" : "replies")
                            </button>
                        }

                        @if (hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" @onclick="() => OpenThreadAsync(msg.Id)" title="Reply in thread">
                                    💬 Reply
                                </button>
                                <div class="emoji-picker-wrapper">
                                    <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)" title="Add reaction">
                                        😀 React
                                    </button>
                                    @if (emojiPickerMessageId == msg.Id)
                                    {
                                        <div class="emoji-picker">
                                            @foreach (var emoji in commonEmojis)
                                            {
                                                <button class="emoji-option" @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                    @emoji
                                                </button>
                                            }
                                        </div>
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-textarea" @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMainKeyDownAsync"
                          placeholder="Message #@activeChannel.Name" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="empty-state">Select a channel to start chatting</div>
        }
    </section>

    @* ── Right Thread Panel ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <header class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </header>

            <div class="thread-root-quote">
                <strong>@threadRootMessage.Author</strong>
                <span class="message-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @foreach (var reply in threadReplies)
                {
                    <div class="message-card">
                        <div class="message-meta">
                            <strong class="message-author">@reply.Author</strong>
                            <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="message-content">@reply.Content</div>

                        @if (reply.Reactions.Count > 0)
                        {
                            <div class="reaction-row">
                                @foreach (var r in reply.Reactions)
                                {
                                    <button class="reaction-badge" @onclick="() => AddReactionAsync(reply.Id, r.Emoji)"
                                            title="@string.Join(", ", r.Users)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-textarea" @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="HandleThreadKeyDownAsync"
                          placeholder="Reply in thread…" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private List<Message> threadReplies = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool threadOpen;

    private string newMessageText = "";
    private string threadReplyText = "";

    private int? hoveredMessageId;
    private int? emojiPickerMessageId;

    private bool isLoadingOlder;
    private bool allOlderLoaded;
    private const int PageSize = 30;

    private ElementReference messageListRef;

    private static readonly string[] commonEmojis = { "👍", "❤️", "😂", "🎉", "😮", "🚀" };

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        allOlderLoaded = false;
        emojiPickerMessageId = null;

        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to reflect cleared unread count
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottomAsync();
    }

    private async Task HandleScrollAsync()
    {
        if (isLoadingOlder || allOlderLoaded)
            return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task LoadOlderMessagesAsync()
    {
        isLoadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        if (older.Count < PageSize)
            allOlderLoaded = true;

        messages.InsertRange(0, older);
        BuildThreadSummaries();
        isLoadingOlder = false;
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        // Group replies by their ReplyToId to build thread summaries
        var replies = messages.Where(m => m.ReplyToId.HasValue).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText))
            return;

        var sent = await ChatService.SendMessageAsync(activeChannelId, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = "";
        await ScrollToBottomAsync();
    }

    private async Task HandleMainKeyDownAsync(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Thread ──
    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadReplyText = "";
        threadOpen = true;
        emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null)
            return;

        var reply = await ChatService.SendMessageAsync(activeChannelId, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);

        // Also add to main message list and update thread summary
        messages.Add(reply);
        BuildThreadSummaries();

        threadReplyText = "";
    }

    // ── Reactions ──
    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        messages = await ChatService.GetMessagesAsync(activeChannelId, 0, messages.Count);

        // Refresh thread replies if thread is open
        if (threadOpen && threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    // ── Helpers ──
    private async Task ScrollToBottomAsync()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 40 ? desc[..37] + "…" : desc;
    }
}
"}

